#!/usr/bin/env node

/**
 * Schema Edit Guard — PreToolUse Hook
 *
 * Blocks Edit tool on LOCKED schema files. These files must never be
 * modified by any tool — they are owned by external systems.
 *
 * LOCKED files (always blocked):
 *   - packages/database/schema/auth.ts      (Better Auth owned)
 *   - packages/database/drizzle/schema.ts    (auto-generated by drizzle-kit)
 *
 * All other files pass through to the existing edit-block-on-escalation.mjs hook.
 *
 * Exit codes:
 *   0 = ALLOW (tool proceeds to next hook)
 *   2 = BLOCK (stderr message shown to agent, tool does NOT execute)
 */

const LOCKED_PATTERNS = [
  /\/schema\/auth\.ts$/, // Better Auth owned — DO NOT MODIFY
  /\/drizzle\/schema\.ts$/, // Auto-generated by drizzle-kit
];

function readStdin() {
  return new Promise((resolve) => {
    let data = "";
    process.stdin.setEncoding("utf8");
    process.stdin.on("data", (chunk) => {
      data += chunk;
    });
    process.stdin.on("end", () => {
      resolve(data);
    });
  });
}

function isLockedFile(filePath) {
  if (!filePath) {
    return false;
  }
  return LOCKED_PATTERNS.some((pattern) => pattern.test(filePath));
}

async function main() {
  const raw = await readStdin();

  let input;
  try {
    input = JSON.parse(raw);
  } catch {
    process.exit(0); // Fail open
  }

  const toolName = (input.tool_name || "").toLowerCase();

  // Only intercept Edit tool
  if (toolName !== "edit") {
    process.exit(0);
  }

  const toolInput = input.tool_input || {};
  const filePath = toolInput.filePath || toolInput.file_path || "";

  if (!isLockedFile(filePath)) {
    process.exit(0); // Not locked — allow (other hooks may still block)
  }

  // ── LOCKED file — hard block ──

  const isAuth = /\/schema\/auth\.ts$/.test(filePath);
  const isDrizzleGenerated = /\/drizzle\/schema\.ts$/.test(filePath);

  const reason = isAuth
    ? [
        "⛔ LOCKED FILE — EDIT BLOCKED on auth.ts",
        "",
        "File: " + filePath,
        "",
        "This file is BETTER AUTH OWNED — DO NOT MODIFY.",
        "These tables are managed by Better Auth's migration system:",
        "  user, session, account, verification,",
        "  organization, member, invitation, apikey",
        "",
        "If you need to extend user data, create an app table with a",
        "foreign key to user.id in packages/database/schema/app/<tablename>.ts",
        "",
        "This block cannot be overridden.",
      ].join("\n")
    : isDrizzleGenerated
      ? [
          "⛔ LOCKED FILE — EDIT BLOCKED on drizzle/schema.ts",
          "",
          "File: " + filePath,
          "",
          "This file is AUTO-GENERATED by drizzle-kit.",
          "Never edit it manually — your changes will be overwritten.",
          "",
          "To change schema:",
          "  1. Edit or create files in packages/database/schema/app/",
          "  2. Run: bun run db:generate",
          "",
          "This block cannot be overridden.",
        ].join("\n")
      : "⛔ LOCKED FILE — " + filePath + " cannot be edited.";

  process.stderr.write(reason + "\n");
  process.exit(2);
}

main().catch(() => {
  process.exit(0); // Fail open
});
